const thDate = (iso) => {
  if (!iso) return "—";
  const m = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const [y, mo, d] = iso.split("-").map(Number);
  return `${d} ${m[mo - 1]} ${y}`;
};
const COAT = { bay: "น้ำตาลแดง", chestnut: "เกาลัด", grey: "แซม", "dark bay": "น้ำตาลเข้ม", brown: "น้ำตาล", "bay/brown": "น้ำตาลแดง", bar: "น้ำตาล" };
const HOME = { nz: "นิวซีแลนด์", aus: "ออสเตรเลีย", arg: "อาร์เจนตินา", thai: "ไทย" };

/* ---------- analysis helpers ---------- */
const TODAY = new Date("2026-06-10");
const ageYMD = (iso) => {
  if (!iso) return null;
  const b = new Date(iso);
  let y = TODAY.getFullYear() - b.getFullYear();
  let m = TODAY.getMonth() - b.getMonth();
  let d = TODAY.getDate() - b.getDate();
  if (d < 0) { m--; d += new Date(TODAY.getFullYear(), TODAY.getMonth(), 0).getDate(); }
  if (m < 0) { y--; m += 12; }
  return `${y} Y ${m} M ${d} D`;
};
const ageYears = (iso) => {
  if (!iso) return null;
  const b = new Date(iso);
  let y = TODAY.getFullYear() - b.getFullYear();
  if (TODAY.getMonth() < b.getMonth() || (TODAY.getMonth() === b.getMonth() && TODAY.getDate() < b.getDate())) y--;
  return y;
};
const yearLevel = (iso) => {
  const a = ageYears(iso);
  if (a == null) return null;
  if (a <= 3) return "Rookie";
  if (a === 4) return "Professional";
  if (a === 5) return "Elite";
  return "Champion";
};
const pct = (n, d) => (d ? Math.round((n / d) * 100) : 0);

/* speed — time format "1/23.12" = 1 นาที 23.12 วินาที */
const timeSecs = (t) => {
  if (typeof t !== "string" || !t.includes("/")) return null;
  const [mn, sc] = t.split("/");
  const m = parseInt(mn), s = parseFloat(sc);
  if (isNaN(m) || isNaN(s)) return null;
  return m * 60 + s;
};
const speedOf = (r) => {
  const s = timeSecs(r.time);
  if (!s || !r.dist) return null;
  return (r.dist / s) * 3.6;
};
const kmh = (v) => (v == null ? null : `${(Math.round(v * 10) / 10).toFixed(1)} km/h`);
const TYPE_LABEL = { colt: "Colt", stallion: "Stallion", gelding: "Gelding", filly: "Filly", mare: "Mare" };
const placeLabel = (p) => {
  if (p === "scratching") return "scratching";
  if (p === 1) return "1st";
  return typeof p === "number" ? `${p}th` : "—";
};

/* running style — from position start / 3rd curve / spurt / finish */
const posVal = (v) => (typeof v === "number" && v >= 1 ? v : null); /* 0 หรือ n/a = นอกกลุ่มนำ */
const runStyle = (r) => {
  if (typeof r.place !== "number") return null;
  const e = posVal(r.ps) ?? posVal(r.p3);
  if (e !== null && e <= 2) return "Leader";
  if (e !== null && e <= 5) return "Prominent";
  if (e !== null && e <= 8) return "Midfield";
  if (r.place <= 3) return "Deep Closer";
  return "Hold-up";
};
const STYLE_INFO = {
  "Leader": { color: "#FF9F45", desc: "ออกซองไว วิ่งขึ้นนำตั้งแต่ช่วงต้น คุมจังหวะเกมจากด้านหน้า" },
  "Prominent": { color: "#58C9A0", desc: "เกาะกลุ่มหัวแถวช่วงต้น กดดัน แล้วหาจังหวะช่วงท้ายเกม" },
  "Midfield": { color: "#5FB3D9", desc: "วิ่งกลางกลุ่ม คุมจังหวะ รอขยับตามสถานการณ์" },
  "Hold-up": { color: "#9B8CE8", desc: "เก็บตัวท้ายกลุ่ม ไหลแซงช่วงท้าย" },
  "Deep Closer": { color: "#5B7CF5", desc: "เก็บแรงช่วงต้น ระเบิดพลังไล่แซงช่วงสุดท้าย" },
};
const analyzeStyle = (runs) => {
  const styles = runs.map(runStyle).filter(Boolean);
  if (!styles.length) return null;
  const count = {};
  styles.forEach((s) => (count[s] = (count[s] || 0) + 1));
  const dist = ["Leader", "Prominent", "Midfield", "Hold-up", "Deep Closer"]
    .filter((k) => count[k])
    .map((k) => ({ k, v: count[k], p: pct(count[k], styles.length) }))
    .sort((a, b) => b.v - a.v);
  const leadStart = runs.filter((r) => posVal(r.ps) !== null && posVal(r.ps) <= 2).length;
  const spurtTop = runs.filter((r) => posVal(r.psp) !== null && posVal(r.psp) <= 3).length;
  return { main: dist[0].k, dist, n: styles.length, leadStartP: pct(leadStart, styles.length), spurtTopP: pct(spurtTop, styles.length) };
};

/* birth-date analysis — Thai zodiac year, day of birth, western sign (เพื่อความบันเทิง) */
const NAKSAT = ["ชวด", "ฉลู", "ขาล", "เถาะ", "มะโรง", "มะเส็ง", "มะเมีย", "มะแม", "วอก", "ระกา", "จอ", "กุน"];
const NAKSAT_TRAIT = [
  "เรียนรู้ไว",
  "ขยันขันแข็ง",
  "กล้าได้กล้าเสีย",
  "นุ่มนวล",
  "สง่างาม",
  "เยือกเย็น",
  "รักอิสระ",
  "ไม่ชอบปะทะ",
  "สร้างเซอร์ไพรส์",
  "ตื่นตัวตลอดเวลา",
  "ซื่อตรง",
  "ใจดี",
];
const DAYS = [
  { name: "อาทิตย์", color: "#F26D6D", trait: "ออกตัวแรงไม่เกรงใคร" },
  { name: "จันทร์", color: "#F5C84C", trait: "วิ่งตามแผนอย่างมีวินัย" },
  { name: "อังคาร", color: "#FF93C4", trait: "ยิ่งโดนกดดันยิ่งฮึด" },
  { name: "พุธ", color: "#58C9A0", trait: "เปลี่ยนจังหวะได้คล่อง" },
  { name: "พฤหัสบดี", color: "#FFA45C", trait: "เด่นเรื่องความสม่ำเสมอ" },
  { name: "ศุกร์", color: "#5BA8F5", trait: "ทำผลงานดีเมื่อบรรยากาศเป็นใจ" },
  { name: "เสาร์", color: "#9D8DF1", trait: "รับแรงกดดันได้ดีที่สุด" },
];
const RASI_BOUND = [[1, 20, "มังกร"], [2, 19, "กุมภ์"], [3, 21, "มีน"], [4, 20, "เมษ"], [5, 21, "พฤษภ"], [6, 21, "เมถุน"], [7, 23, "กรกฎ"], [8, 23, "สิงห์"], [9, 23, "กันย์"], [10, 23, "ตุลย์"], [11, 22, "พิจิก"], [12, 22, "ธนู"], [12, 32, "มังกร"]];
const RASI_TRAIT = { "มังกร": "ก้าวทีละก้าวแต่มั่นคง", "กุมภ์": "ชอบทำอะไรต่างจากคนอื่น", "มีน": "สัมผัสจังหวะได้ดี", "เมษ": "ทรงพลัง", "พฤษภ": "ดื้อนิดหน่อยแต่ไว้ใจได้", "เมถุน": "เดาทางยาก", "กรกฎ": "วิ่งดีในตำแหน่งที่คุ้นเคย", "สิงห์": "ยิ่งมีคนเชียร์ยิ่งวิ่งสนุก", "กันย์": "ฟอร์มสม่ำเสมอ", "ตุลย์": "วิ่งเรียบลื่นไม่หวือหวา", "พิจิก": "เก็บอาการเก่ง", "ธนู": "ยิ่งระยะไกลยิ่งสนุก" };
const birthInfo = (iso) => {
  if (!iso) return null;
  const dt = new Date(iso + "T00:00:00");
  const [y, m, d] = iso.split("-").map(Number);
  const nk = (((y - 4) % 12) + 12) % 12;
  const day = DAYS[dt.getDay()];
  let rasi = "มังกร";
  for (const [bm, bd, name] of RASI_BOUND) { if (m < bm || (m === bm && d < bd)) { rasi = name; break; } }
  return { naksat: NAKSAT[nk], naksatTrait: NAKSAT_TRAIT[nk], day, rasi, rasiTrait: RASI_TRAIT[rasi] };
};

/* ไบโอสั้น ๆ ใต้บัตร — ชื่อ + ที่มา + จุดเด่น + นิสัยขัดแย้งน่ารัก ๆ (ไม่ใส่คำนำหน้า) */
const moeBio = (h) => {
  const name = (h.th || h.name || "?").split(" ")[0];
  const origin = { aus: "สาวออสซี่", nz: "สาวกีวี", arg: "สาวอาร์เจนตินา", thai: "สาวไทย" }[h.country] || "สาวม้า";
  const hook = {
    "Leader": "ฝีเท้าต้น",
    "Prominent": "สายวิ่งกดดัน",
    "Midfield": "คุมเกมกลางกลุ่ม",
    "Hold-up": "วิ่งรอจังหวะ",
    "Deep Closer": "ฝีเท้าปลาย",
  }[h.style ? h.style.main : "Midfield"];
  const bi = h.bday ? birthInfo(h.bday) : null;
  const traitA = bi ? bi.naksatTrait.split(" ")[0] : "ขยัน";
  const soft = bi ? {
    "อาทิตย์": "พึ่งพาได้", "จันทร์": "อ่อนโยน", "อังคาร": "ใจสู้",
    "พุธ": "หัวไว", "พฤหัสบดี": "ใจเย็น", "ศุกร์": "ยิ้มเก่ง", "เสาร์": "สุขุม",
  }[bi.day.name] : "เป็นมิตร";
  const champ = h.wins > 0 ? ` · เจ้าของ ${h.wins} แชมป์` : "";
  return `${name} ${origin}${hook} ${traitA} และ${soft}${champ} ✦`;
};

