/* วงแหวนค่าเหนื่อยรอบไอคอน/โปรไฟล์ — stam=0..1 · ring เป็น conic-gradient รอบนอก */
const StaminaRing = ({ children, size, stam }) => {
  if (stam == null) return children;
  const p = Math.max(0, Math.min(1, stam));
  const col = p < 0.2 ? "#D06262" : p < 0.4 ? "#E8A23D" : "#58C9A0";
  const ringW = Math.max(3, Math.round(size * 0.085));
  const deg = p * 360;
  const box = size + ringW * 2 + 4;
  return (
    <div style={{ position: "relative", width: box, height: box, display: "inline-flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{
        position: "absolute", inset: 0, borderRadius: "50%",
        background: `conic-gradient(${col} ${deg}deg, rgba(0,0,0,0.10) ${deg}deg 360deg)`,
        WebkitMask: `radial-gradient(farthest-side, transparent calc(100% - ${ringW}px), #000 calc(100% - ${ringW}px))`,
        mask: `radial-gradient(farthest-side, transparent calc(100% - ${ringW}px), #000 calc(100% - ${ringW}px))`,
      }} />
      <div style={{ position: "relative", lineHeight: 0 }}>{children}</div>
    </div>
  );
};

const Cloth = ({ n, size = 34 }) => {
  const [bg, fg] = CLOTH[n] || [T.soft, T.muted];
  return (
    <div style={{
      width: size, height: size, minWidth: size, background: bg, color: fg,
      display: "flex", alignItems: "center", justifyContent: "center",
      fontFamily: "'FC Orbit','IBM Plex Mono',monospace", fontWeight: 700, fontSize: size * 0.45,
      borderRadius: 2, border: "1px solid rgba(0,0,0,0.3)",
      
    }}><span>{n ?? "–"}</span></div>
  );
};

const PlacePill = ({ p }) => {
  let bg = T.soft, fg = T.muted, bd = T.line;
  if (p === 1) { bg = T.gold; fg = "#FFFFFF"; bd = T.gold; }
  else if (p === 2 || p === 3) { bg = "rgba(109,169,140,0.16)"; fg = "#8FCBAE"; bd = "rgba(109,169,140,0.4)"; }
  else if (p === "scratching") { bg = "rgba(199,123,139,0.16)"; fg = "#D89AA6"; bd = "rgba(199,123,139,0.4)"; }
  return (
    <span style={{
      padding: "3px 9px", borderRadius: 2, fontSize: 12, fontWeight: 700,
      background: bg, color: fg, border: `1px solid ${bd}`, whiteSpace: "nowrap",
      fontFamily: "'FC Orbit','Prompt',sans-serif", display: "inline-block",
    }}><span>{placeLabel(p)}</span></span>
  );
};

/* past-5-runs form string → chips */
const FormChips = ({ form }) => {
  if (!form) return null;
  const runs = String(form).replace(/\(\d+\)/g, " ").trim().split(/[-\s]+/).filter(Boolean);
  return (
    <div style={{ display: "flex", gap: 4 }}>
      {runs.slice(-5).map((r, i) => {
        const n = parseInt(r);
        const win = n === 1, pod = n === 2 || n === 3;
        return (
          <span key={i} title={`ผลครั้งก่อน: ${r}`} style={{
            width: 22, height: 22, display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 11, fontFamily: "'FC Orbit','IBM Plex Mono',monospace", fontWeight: 600, borderRadius: 2,
            background: win ? T.gold : pod ? "rgba(109,169,140,0.16)" : T.soft,
            color: win ? "#fff" : pod ? T.mint : T.muted,
            border: `1px solid ${win ? T.gold : pod ? "rgba(109,169,140,0.4)" : T.line}`,
          }}>{r}</span>
        );
      })}
    </div>
  );
};

