/* Story Mode introduction player · visual-novel style, tap to advance */
function StoryIntro({ onFinish, trainer, setTrainer }) {
  const [i, setI] = useState(0);
  const [nameDone, setNameDone] = useState(false);
  const cur = INTRO_STORY[i];
  const needName = cur && cur.name && !nameDone;

  const advance = () => {
    if (needName) return;            /* must fill name first */
    if (i < INTRO_STORY.length - 1) { setI((n) => n + 1); return; }
    onFinish();                      /* last line → Choose your SAOW MA */
  };

  /* render text, substituting trainer name */
  const renderText = (s) => {
    const nm = trainer.trim() || "เทรนเนอร์";
    return s.replace("[ชื่อผู้เล่น]", nm);
  };

  const isHero = cur && cur.hero;
  return (
    <div onClick={advance}
      style={{ position: "fixed", inset: 0, zIndex: 60, cursor: needName ? "default" : "pointer",
        background: "radial-gradient(130% 100% at 50% 18%, #2A2540 0%, #1C1830 55%, #110F22 100%)",
        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
        padding: "32px 24px", overflow: "hidden" }}>
      {/* drifting MA-therial sparkles */}
      {[{t:"14%",l:"16%",s:14,d:"0s",c:"#B7A6F2"},{t:"22%",l:"80%",s:10,d:".6s",c:"#7BC6F0"},
        {t:"74%",l:"22%",s:12,d:".3s",c:"#F49ACB"},{t:"66%",l:"82%",s:13,d:".9s",c:"#F6D27B"}].map((sp,k)=>(
        <span key={k} aria-hidden style={{ position:"absolute", top:sp.t, left:sp.l, color:sp.c, fontSize:sp.s,
          animation:`twinkle 2.4s ease-in-out ${sp.d} infinite`, textShadow:"0 0 10px rgba(180,160,240,0.8)" }}>✦</span>
      ))}

      <div key={i} style={{ maxWidth: 560, textAlign: "center", animation: "tbcFadeIn 0.5s ease both" }}>
        {cur && cur.letter && (
          <div style={{ fontFamily: "'FC Orbit','IBM Plex Mono',monospace", fontSize: 10,
            letterSpacing: "0.22em", color: "#8E84C8", marginBottom: 16 }}>· จดหมายแต่งตั้ง ·</div>
        )}
        <div style={{
          fontFamily: "'FC Orbit','Prompt',sans-serif",
          fontWeight: isHero ? 800 : 500,
          fontSize: isHero ? 40 : (cur && cur.welcome ? 24 : 21),
          lineHeight: 1.7,
          color: isHero ? "#fff" : "#EDE9FB",
          letterSpacing: isHero ? "0.08em" : "0.01em",
          textShadow: isHero ? "0 4px 30px rgba(150,120,240,0.6)" : "0 2px 14px rgba(0,0,0,0.4)",
        }}>
          {cur ? renderText(cur.t) : ""}
        </div>

        {/* trainer name input at the letter greeting */}
        {needName && (
          <div onClick={(e) => e.stopPropagation()} style={{ marginTop: 26, display: "flex",
            flexDirection: "column", alignItems: "center", gap: 12 }}>
            <input
              autoFocus value={trainer} onChange={(e) => setTrainer(e.target.value)}
              onKeyDown={(e) => { if (e.key === "Enter" && trainer.trim()) { setNameDone(true); setI((n)=>n+1); } }}
              placeholder="กรอกชื่อเทรนเนอร์ของคุณ" maxLength={20}
              style={{ width: "min(80vw, 320px)", textAlign: "center", fontSize: 18, padding: "12px 18px",
                borderRadius: 4, border: "1px solid #6C5DD3", background: "rgba(255,255,255,0.95)",
                color: "#2E2A45", outline: "none" }} />
            <button disabled={!trainer.trim()}
              onClick={() => { setNameDone(true); setI((n) => n + 1); }}
              style={{ border: "2px solid #fff", background: trainer.trim() ? "linear-gradient(180deg,#B07BE0,#7A4FC0)" : "#4A4470",
                color: "#fff", fontFamily: "'FC Orbit','Prompt',sans-serif", fontWeight: 800, fontSize: 15,
                padding: "10px 34px", borderRadius: 99, cursor: trainer.trim() ? "pointer" : "not-allowed",
                opacity: trainer.trim() ? 1 : 0.55 }}>
              ยืนยัน
            </button>
          </div>
        )}
      </div>

      {/* progress + tap hint */}
      {!needName && (
        <div style={{ position: "absolute", bottom: 30, display: "flex", flexDirection: "column",
          alignItems: "center", gap: 10 }}>
          <div style={{ fontFamily: "'FC Orbit','IBM Plex Mono',monospace", fontSize: 10,
            letterSpacing: "0.2em", color: "rgba(237,233,251,0.5)",
            animation: "introBlink 1.6s ease-in-out infinite" }}>แตะเพื่อไปต่อ ▸</div>
          <div style={{ fontFamily: "'IBM Plex Mono',monospace", fontSize: 9, color: "rgba(237,233,251,0.35)" }}>
            {i + 1} / {INTRO_STORY.length}
          </div>
        </div>
      )}

      {/* skip */}
      <button onClick={(e) => { e.stopPropagation(); onFinish(); }}
        style={{ position: "absolute", top: 18, right: 18, border: "1px solid rgba(255,255,255,0.25)",
          background: "rgba(255,255,255,0.06)", color: "rgba(237,233,251,0.7)", fontSize: 11,
          fontFamily: "'FC Orbit','Prompt',sans-serif", padding: "6px 16px", borderRadius: 99, cursor: "pointer" }}>
        ข้าม ⏭
      </button>
      <style>{`@keyframes tbcFadeIn { 0% { opacity: 0; transform: translateY(10px); } 100% { opacity: 1; transform: translateY(0); } }`}</style>
    </div>
  );
}

